hooks.command:
STDIN=$(cat); FILE=$(echo "$STDIN" | jq -r '.tool_input.file_path // .tool_response.filePath // ""'); if echo "$FILE" | grep -qE 'index\.html$'; then node --input-type=module <<'JSEOF' 2>&1 | grep -E '(SyntaxError|Error|error)' | head -5 || true
import { readFileSync } from 'fs';
const src = readFileSync('/home/user/CMCteams/index.html','utf8');
const m = src.match(/<script[^>]*>([\s\S]*?)<\/script>/g);
if(m){const js=m.map(s=>s.replace(/<script[^>]*>/,'').replace(/<\/script>/,'')).join('\n'); new Function(js);}
console.log('JS OK');
JSEOF
fi
